using UnityEngine;
using UnityEngine.Tilemaps;
using System.Collections.Generic;
using TowerDefense.Tower;

public class TowerSlotDetector : MonoBehaviour
{
    [Header("Settings")]
    [SerializeField] private Tilemap buildableTilemap;
    [SerializeField] private TileBase buildableTile;
    [SerializeField] private GameObject towerSlotPrefab;
    [SerializeField] private Transform towerSlotsContainer;

    [Header("Gizmo Settings")]
    [SerializeField] private Color slotColor = Color.green;

    [ContextMenu("Detect Tower Slots")]
    public void DetectTowerSlots()
    {
        if (buildableTilemap == null || towerSlotPrefab == null) return;

        ClearExistingSlots();

        BoundsInt bounds = buildableTilemap.cellBounds;
        TileBase[] allTiles = buildableTilemap.GetTilesBlock(bounds);

        for (int x = bounds.xMin; x < bounds.xMax; x++)
        {
            for (int y = bounds.yMin; y < bounds.yMax; y++)
            {
                Vector3Int cell = new Vector3Int(x, y, 0);
                TileBase tile = buildableTilemap.GetTile(cell);

                if (tile != null && tile == buildableTile)
                {
                    CreateTowerSlot(cell);
                }
            }
        }

        Debug.Log($"Created {towerSlotsContainer.childCount} tower slots");
    }

    private void CreateTowerSlot(Vector3Int cell)
    {
        Vector3 worldPos = buildableTilemap.CellToWorld(cell);
        worldPos += new Vector3(0.5f, 0.5f, 0);

        GameObject slotObj = Instantiate(towerSlotPrefab, worldPos, Quaternion.identity);
        slotObj.name = $"TowerSlot_{cell.x}_{cell.y}";
        slotObj.transform.SetParent(towerSlotsContainer);

        TowerSlot slot = slotObj.GetComponent<TowerSlot>();
        if (slot != null)
        {
            Debug.Log($"Created tower slot at {cell}");
        }
    }

    [ContextMenu("Clear Tower Slots")]
    public void ClearExistingSlots()
    {
        for (int i = towerSlotsContainer.childCount - 1; i >= 0; i--)
        {
            DestroyImmediate(towerSlotsContainer.GetChild(i).gameObject);
        }
    }

    private void OnDrawGizmosSelected()
    {
        if (buildableTilemap == null) return;

        BoundsInt bounds = buildableTilemap.cellBounds;

        for (int x = bounds.xMin; x < bounds.xMax; x++)
        {
            for (int y = bounds.yMin; y < bounds.yMax; y++)
            {
                Vector3Int cell = new Vector3Int(x, y, 0);
                TileBase tile = buildableTilemap.GetTile(cell);

                if (tile != null && tile == buildableTile)
                {
                    Vector3 worldPos = buildableTilemap.CellToWorld(cell);
                    worldPos += new Vector3(0.5f, 0.5f, 0);

                    Gizmos.color = slotColor;
                    Gizmos.DrawWireSphere(worldPos, 0.4f);
                }
            }
        }
    }
}

using UnityEngine;

namespace TowerDefense.Core
{
    public abstract class Singleton<T> : MonoBehaviour where T : MonoBehaviour
    {
        private static T _instance;
        private static readonly object _lock = new object();
        private static bool _applicationIsQuitting = false;

        public static T Instance
        {
            get
            {
                if (_applicationIsQuitting)
                {
                    Debug.LogWarning($"[Singleton] Instance '{typeof(T)}' already destroyed. Returning null.");
                    return null;
                }

                lock (_lock)
                {
                    if (_instance == null)
                    {
                        _instance = FindObjectOfType<T>();

                        if (_instance == null)
                        {
                            GameObject singleton = new GameObject($"(Singleton) {typeof(T)}");
                            _instance = singleton.AddComponent<T>();
                            DontDestroyOnLoad(singleton);
                        }
                    }
                    return _instance;
                }
            }
        }

        protected virtual void Awake()
        {
            if (_instance == null)
            {
                _instance = this as T;
                transform.SetParent(null);
                DontDestroyOnLoad(gameObject);
            }
            else if (_instance != this)
            {
                Destroy(gameObject);
            }
        }

        protected virtual void OnDestroy()
        {
            if (_instance == this)
            {
                _applicationIsQuitting = true;
            }
        }
    }
}

using System.Collections.Generic;
using UnityEngine;
using UnityEngine.Tilemaps;
using TowerDefense.Data;

namespace TowerDefense.Map
{
    public class LevelBuilder : MonoBehaviour
    {
        [Header("Tilemaps")]
        [SerializeField] private Tilemap groundMap;
        [SerializeField] private Tilemap pathMap;
        [SerializeField] private Tilemap buildSlotMap;
        [SerializeField] private Tilemap decorationMap;

        [Header("Tile Assets")]
        [SerializeField] private TileBase grassTile;
        [SerializeField] private TileBase pathTile;
        [SerializeField] private TileBase buildSlotTile;
        [SerializeField] private TileBase decoStoneTile;
        [SerializeField] private TileBase decoGrassTile1;
        [SerializeField] private TileBase decoGrassTile2;
        [SerializeField] private TileBase decoGrassTile3;

        [Header("Path Tiles (Auto-selected)")]
        [SerializeField] private TileBase pathHorizontalTop;
        [SerializeField] private TileBase pathHorizontalBottom;
        [SerializeField] private TileBase pathVerticalLeft;
        [SerializeField] private TileBase pathVerticalRight;
        [SerializeField] private TileBase pathCornerTopRight;
        [SerializeField] private TileBase pathCornerTopLeft;
        [SerializeField] private TileBase pathCornerBottomRight;
        [SerializeField] private TileBase pathCornerBottomLeft;

        [Header("Prefabs")]
        [SerializeField] private GameObject towerSlotPrefab;

        private List<Tower.TowerSlot> _towerSlots = new List<Tower.TowerSlot>();
        private Vector3Int _startCell;
        private Vector3Int _endCell;

        public List<Tower.TowerSlot> TowerSlots => _towerSlots;
        public Vector3Int StartCell => _startCell;
        public Vector3Int EndCell => _endCell;

        public void BuildLevel(LevelData levelData)
        {
            if (levelData?.mapRows == null || levelData.mapRows.Length == 0)
            {
                Debug.LogError("LevelData has no map rows!");
                return;
            }

            ClearAll();

            int height = levelData.mapRows.Length;
            int width = levelData.mapRows[0].Length;

            // Populate a set of path/build cells for neighbor lookup
            var pathCells = new HashSet<Vector3Int>();
            var buildCells = new HashSet<Vector3Int>();
            var decoCells = new HashSet<Vector3Int>();

            // First pass: collect all cell positions
            for (int row = 0; row < height; row++)
            {
                string line = levelData.mapRows[row];
                for (int col = 0; col < Mathf.Min(line.Length, width); col++)
                {
                    char c = line[col];
                    var cell = new Vector3Int(col, height - 1 - row, 0);

                    switch (c)
                    {
                        case 'P': case 'S': case 'E':
                            pathCells.Add(cell);
                            if (c == 'S') _startCell = cell;
                            if (c == 'E') _endCell = cell;
                            break;
                        case 'B':
                            buildCells.Add(cell);
                            break;
                        case 'D':
                            decoCells.Add(cell);
                            break;
                    }
                }
            }

            // Second pass: paint tiles
            for (int row = 0; row < height; row++)
            {
                string line = levelData.mapRows[row];
                for (int col = 0; col < Mathf.Min(line.Length, width); col++)
                {
                    char c = line[col];
                    var cell = new Vector3Int(col, height - 1 - row, 0);

                    // Ground: fill everywhere that has content
                    if (c != '.')
                    {
                        groundMap.SetTile(cell, grassTile);
                    }

                    switch (c)
                    {
                        case 'P': case 'S': case 'E':
                            pathMap.SetTile(cell, SelectPathTile(cell, pathCells));
                            break;
                        case 'B':
                            buildSlotMap.SetTile(cell, buildSlotTile);
                            break;
                        case 'D':
                            decorationMap.SetTile(cell, PickRandomDeco());
                            break;
                    }
                }
            }

            // Generate TowerSlots
            GenerateTowerSlots();

            Debug.Log($"Level '{levelData.levelName}' built: {width}x{height}, " +
                      $"path={pathCells.Count}, build={buildCells.Count}, deco={decoCells.Count}");
        }

        private TileBase SelectPathTile(Vector3Int cell, HashSet<Vector3Int> pathCells)
        {
            bool up = pathCells.Contains(cell + Vector3Int.up);
            bool down = pathCells.Contains(cell + Vector3Int.down);
            bool left = pathCells.Contains(cell + Vector3Int.left);
            bool right = pathCells.Contains(cell + Vector3Int.right);

            // Diagonal neighbors - distinguish parallel rows from junctions
            bool upLeft = pathCells.Contains(cell + Vector3Int.up + Vector3Int.left);
            bool upRight = pathCells.Contains(cell + Vector3Int.up + Vector3Int.right);
            bool downLeft = pathCells.Contains(cell + Vector3Int.down + Vector3Int.left);
            bool downRight = pathCells.Contains(cell + Vector3Int.down + Vector3Int.right);

            // A "parallel row" means the perpendicular neighbor also extends in the
            // same horizontal/vertical direction (both diagonals on that side are path).
            bool upIsParallel = up && upLeft && upRight;
            bool downIsParallel = down && downLeft && downRight;
            bool leftIsParallel = left && upLeft && downLeft;
            bool rightIsParallel = right && upRight && downRight;

            // --- Horizontal road cells ---
            if (left && right)
            {
                // If there's a parallel row, use straight tile based on which half
                if (upIsParallel) return pathHorizontalBottom; // parallel above → bottom row
                if (downIsParallel) return pathHorizontalTop;  // parallel below → top row

                // No parallel row → junction cell, determine corner type
                if (up && !down) return pathHorizontalBottom; // junction above, still bottom
                if (down && !up) return pathHorizontalTop;     // junction below, still top

                // Both up and down are junctions (no parallel row)
                // Use diagonal analysis for corner type
                if (!downRight && upLeft) return pathCornerBottomRight;
                if (!downLeft && upRight) return pathCornerBottomLeft;
                if (!upRight && downLeft) return pathCornerTopRight;
                if (!upLeft && downRight) return pathCornerTopLeft;

                return up ? pathHorizontalBottom : pathHorizontalTop;
            }

            // --- Vertical road cells ---
            if (up && down)
            {
                if (rightIsParallel) return pathVerticalLeft;  // parallel right → left column
                if (leftIsParallel) return pathVerticalRight;  // parallel left → right column

                if (right && !left) return pathVerticalLeft;
                if (left && !right) return pathVerticalRight;

                // Both left and right are junctions
                if (!downRight && upLeft) return pathCornerBottomRight;
                if (!downLeft && upRight) return pathCornerBottomLeft;
                if (!upRight && downLeft) return pathCornerTopRight;
                if (!upLeft && downRight) return pathCornerTopLeft;

                return right ? pathVerticalLeft : pathVerticalRight;
            }

            // --- Simple corners: exactly 2 orthogonal neighbors ---
            if (up && right && !down && !left) return pathCornerBottomLeft;
            if (up && left && !down && !right) return pathCornerBottomRight;
            if (down && right && !up && !left) return pathCornerTopLeft;
            if (down && left && !up && !right) return pathCornerTopRight;

            // --- Edge cells (single perpendicular neighbor) ---
            if (left || right) return up ? pathHorizontalBottom : pathHorizontalTop;
            if (up || down) return right ? pathVerticalLeft : pathVerticalRight;

            return pathTile;
        }

        private TileBase PickRandomDeco()
        {
            float r = Random.value;
            if (r < 0.4f) return decoGrassTile1;
            if (r < 0.7f) return decoGrassTile2;
            if (r < 0.9f) return decoGrassTile3;
            return decoStoneTile;
        }

        private void GenerateTowerSlots()
        {
            if (buildSlotMap == null || towerSlotPrefab == null) return;

            _towerSlots.Clear();

            // 找到或创建 BuildSlots 父对象
            Transform buildSlotsParent = null;
            var existingParent = GameObject.Find("建造槽");
            if (existingParent == null) existingParent = GameObject.Find("BuildSlots");
            if (existingParent != null)
            {
                // 清除已有的旧 TowerSlot 子对象
                for (int i = existingParent.transform.childCount - 1; i >= 0; i--)
                {
                    DestroyImmediate(existingParent.transform.GetChild(i).gameObject);
                }
                buildSlotsParent = existingParent.transform;
            }

            BoundsInt bounds = buildSlotMap.cellBounds;

            for (int x = bounds.xMin; x < bounds.xMax; x++)
            {
                for (int y = bounds.yMin; y < bounds.yMax; y++)
                {
                    Vector3Int cellPosition = new Vector3Int(x, y, 0);
                    if (buildSlotMap.GetTile(cellPosition) == null) continue;

                    Vector3 worldPosition = buildSlotMap.CellToWorld(cellPosition);
                    worldPosition += new Vector3(0.5f, 0.5f, 0);

                    GameObject slotObj = Instantiate(towerSlotPrefab, worldPosition, Quaternion.identity);
                    slotObj.name = $"TowerSlot_{x}_{y}";

                    // 设置父对象
                    if (buildSlotsParent != null)
                    {
                        slotObj.transform.SetParent(buildSlotsParent, true);
                    }

                    Tower.TowerSlot slot = slotObj.GetComponent<Tower.TowerSlot>();
                    if (slot != null) _towerSlots.Add(slot);
                }
            }

            Debug.Log($"Generated {_towerSlots.Count} tower slots");
        }

        public void ClearAll()
        {
            // Destroy existing tower slots
            foreach (var slot in _towerSlots)
            {
                if (slot != null) Destroy(slot.gameObject);
            }
            _towerSlots.Clear();

            // Also destroy any TowerSlot objects in BuildSlots parent
            var buildSlotsObj = GameObject.Find("建造槽");
            if (buildSlotsObj == null) buildSlotsObj = GameObject.Find("BuildSlots");
            if (buildSlotsObj != null)
            {
                for (int i = buildSlotsObj.transform.childCount - 1; i >= 0; i--)
                {
                    DestroyImmediate(buildSlotsObj.transform.GetChild(i).gameObject);
                }
            }

            groundMap?.ClearAllTiles();
            pathMap?.ClearAllTiles();
            buildSlotMap?.ClearAllTiles();
            decorationMap?.ClearAllTiles();
        }

        /// <summary>
        /// Get ordered path waypoints from start to end by following path tiles.
        /// </summary>
        public List<Vector3> GetPathWaypoints()
        {
            var waypoints = new List<Vector3>();
            if (pathMap == null) return waypoints;

            var visited = new HashSet<Vector3Int>();
            var current = _startCell;

            while (current != null && !visited.Contains(current) && pathMap.GetTile(current) != null)
            {
                visited.Add(current);
                waypoints.Add(pathMap.CellToWorld(current) + new Vector3(0.5f, 0.5f, 0));

                if (current == _endCell) break;

                // Find next unvisited path neighbor
                Vector3Int? next = null;
                foreach (var dir in new[] { Vector3Int.up, Vector3Int.down, Vector3Int.left, Vector3Int.right })
                {
                    var neighbor = current + dir;
                    if (!visited.Contains(neighbor) && pathMap.GetTile(neighbor) != null)
                    {
                        next = neighbor;
                        break;
                    }
                }

                if (next.HasValue) current = next.Value;
                else break;
            }

            return waypoints;
        }
    }
}

using UnityEngine;
using TowerDefense.Tower;

public class BuildButtonManager : MonoBehaviour
{
    public static BuildButtonManager Instance { get; private set; }

    [Tooltip("建造按钮预制体")]
    public GameObject buildButtonPrefab;

    [Tooltip("Canvas引用")]
    public Canvas uiCanvas;

    [Tooltip("按钮偏移")]
    public Vector2 buttonOffset = new Vector2(0, 50);

    private GameObject _currentButton;
    private TowerSlot _currentSlot;

    private void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
        }
        else
        {
            Destroy(gameObject);
        }
    }

    private void Start()
    {
        if (uiCanvas == null)
        {
            uiCanvas = FindObjectOfType<Canvas>();
        }
    }

    /// <summary>
    /// 显示建造按钮
    /// </summary>
    public void ShowBuildButton(TowerSlot slot)
    {
        // 如果有其他按钮，先隐藏
        HideBuildButton();

        if (buildButtonPrefab == null || uiCanvas == null)
        {
            Debug.LogError("BuildButtonManager: Missing prefab or Canvas!");
            return;
        }

        // 计算按钮位置
        Vector3 worldPos = Camera.main.WorldToScreenPoint(slot.transform.position);
        worldPos += new Vector3(buttonOffset.x, buttonOffset.y, 0);

        // 实例化按钮
        _currentButton = Instantiate(buildButtonPrefab);
        _currentButton.transform.SetParent(uiCanvas.transform, false);
        _currentButton.transform.position = worldPos;

        // 绑定事件
        UnityEngine.UI.Button button = _currentButton.GetComponent<UnityEngine.UI.Button>();
        if (button != null)
        {
            button.onClick.AddListener(() => OnBuildButtonClicked(slot));
        }

        _currentSlot = slot;
        Debug.Log($"Build button shown for slot: {slot.name}");
    }

    /// <summary>
    /// 隐藏建造按钮
    /// </summary>
    public void HideBuildButton()
    {
        if (_currentButton != null)
        {
            Destroy(_currentButton);
            _currentButton = null;
        }
        _currentSlot = null;
    }

    /// <summary>
    /// 建造按钮点击
    /// </summary>
    private void OnBuildButtonClicked(TowerSlot slot)
    {
        Debug.Log("Build button clicked!");

        // 先隐藏按钮
        HideBuildButton();

        // 让槽位自己处理建造逻辑
        // 这里我们直接调用一个方法
        slot.OnBuildButtonClickedByManager();
    }

    /// <summary>
    /// 检查当前是否显示了按钮
    /// </summary>
    public bool IsButtonShowing()
    {
        return _currentButton != null;
    }
}

using UnityEngine;
using UnityEngine.UI;
using TowerDefense.Data;
using TowerDefense.Tower;
using TowerDefense.Core;

namespace TowerDefense.UI
{
    public class TowerSelectPanel : MonoBehaviour
    {
        [Header("References")]
        [SerializeField] private GameObject _panel;
        [SerializeField] private Transform _towerButtonContainer;
        [SerializeField] private GameObject _towerButtonPrefab;
        [SerializeField] private Text _slotInfoText;

        [Header("Text Settings")]
        [SerializeField] private Font _buttonFont;


        [Header("Tower Data")]
        [SerializeField] private TowerData[] _availableTowers;

        private TowerSlot _currentSlot;
        private TowerData[] _towerDatas;

        private void Awake()
        {
            Debug.Log($"TowerSelectPanel Awake - _panel: {_panel != null}, _container: {_towerButtonContainer != null}, _prefab: {_towerButtonPrefab != null}, _text: {_slotInfoText != null}");

            if (_panel != null)
            {
                _panel.SetActive(false);
            }

            LoadTowerData();
        }

        private void LoadTowerData()
        {
            if (_availableTowers != null && _availableTowers.Length > 0)
            {
                _towerDatas = _availableTowers;
            }
            else
            {
                _towerDatas = Resources.LoadAll<TowerData>("Data/Towers");

                if (_towerDatas.Length == 0)
                {
                    _towerDatas = Resources.LoadAll<TowerData>("Data");
                }
            }
        }

        public void Show(TowerSlot slot)
        {
            _currentSlot = slot;

            if (_panel == null)
            {
                Debug.LogWarning("⚠️ TowerSelectPanel 的 _panel 字段未设置！");
                return;
            }

            RefreshTowerButtons();
            _panel.SetActive(true);
        }

        public void Hide()
        {
            _currentSlot = null;

            if (_panel != null)
            {
                _panel.SetActive(false);
            }
        }

        private void RefreshTowerButtons()
        {
            foreach (Transform child in _towerButtonContainer)
            {
                Destroy(child.gameObject);
            }

            foreach (var towerData in _towerDatas)
            {
                CreateTowerButton(towerData);
            }
        }

        private void CreateTowerButton(TowerData towerData)
        {
            GameObject buttonObj;

            if (_towerButtonPrefab == null)
            {
                buttonObj = new GameObject($"TowerButton_{towerData.towerName}");
                buttonObj.transform.SetParent(_towerButtonContainer, false);

                Button button = buttonObj.AddComponent<Button>();
                Image bgImage = buttonObj.AddComponent<Image>();
                bgImage.color = new Color(0.4f, 0.4f, 0.6f);

                RectTransform buttonRect = buttonObj.GetComponent<RectTransform>();
                buttonRect.sizeDelta = new Vector2(70, 85);

                if (towerData.icon != null)
                {
                    GameObject iconObj = new GameObject("Icon");
                    iconObj.transform.SetParent(buttonObj.transform, false);

                    Image iconImage = iconObj.AddComponent<Image>();
                    iconImage.sprite = towerData.icon;
                    iconImage.preserveAspect = true;

                    RectTransform iconRect = iconObj.GetComponent<RectTransform>();
                    iconRect.anchorMin = new Vector2(0.5f, 0.4f);
                    iconRect.anchorMax = new Vector2(0.5f, 1f);
                    iconRect.offsetMin = new Vector2(-30, 0);
                    iconRect.offsetMax = new Vector2(30, 0);
                }

                GameObject textObj = new GameObject("Text");
                textObj.transform.SetParent(buttonObj.transform, false);

                Outline outline = textObj.AddComponent<Outline>();
                outline.effectColor = Color.black;
                outline.effectDistance = new Vector2(2, -2);

                Text text = textObj.AddComponent<Text>();
                text.text = $"{GetTowerPrice(towerData)}";

                if (_buttonFont != null)
                {
                    text.font = _buttonFont;
                }

                text.fontSize = 26;
                text.fontStyle = FontStyle.Bold;
                text.alignment = TextAnchor.LowerCenter;
                text.color = new Color(1f, 0.9f, 0f);
                text.horizontalOverflow = HorizontalWrapMode.Overflow;
                text.verticalOverflow = VerticalWrapMode.Overflow;

                RectTransform textRect = textObj.GetComponent<RectTransform>();
                textRect.anchorMin = Vector2.zero;
                textRect.anchorMax = new Vector2(1f, 0.35f);
                textRect.offsetMin = Vector2.zero;
                textRect.offsetMax = Vector2.zero;

                bool canAfford = GameManager.Instance.HasEnoughGold(GetTowerPrice(towerData));
            button.interactable = canAfford;
            Debug.Log($"🔘 [动态按钮] 添加点击监听器: {towerData.towerName}");
            button.onClick.AddListener(() => {
                Debug.Log($"🖱️ [动态按钮] Lambda被调用！");
                OnTowerSelected(towerData);
            });
            Debug.Log($"🔘 [动态按钮] 点击监听器已添加！");

            if (!canAfford)
                {
                    bgImage.color = new Color(0.3f, 0.3f, 0.3f);
                }
            }
            else
            {
                buttonObj = Instantiate(_towerButtonPrefab, _towerButtonContainer);
                buttonObj.name = $"TowerButton_{towerData.towerName}";

                TowerButton towerButton = buttonObj.GetComponent<TowerButton>();
                if (towerButton != null)
                {
                    towerButton.Initialize(towerData, this);
                    Debug.Log($"📌 TowerButton 组件已初始化: {towerData.towerName}");
                }
                else
                {
                    Debug.LogWarning($"⚠️ TowerButton 预制体没有 TowerButton 组件，使用手动设置");
                    SetupButtonManually(buttonObj, towerData);
                }
            }
        }

        private int GetTowerPrice(TowerData towerData)
        {
            if (towerData.levels != null && towerData.levels.Length > 0)
            {
                return towerData.levels[0].cost;
            }
            return 0;
        }

        private void SetupButtonManually(GameObject buttonObj, TowerData towerData)
        {
            Text nameText = buttonObj.GetComponentInChildren<Text>();
            if (nameText != null)
            {
                nameText.text = towerData.towerName;
            }

            Image[] images = buttonObj.GetComponentsInChildren<Image>();
            foreach (var img in images)
            {
                if (img.gameObject != buttonObj && towerData.icon != null && img.sprite == null)
                {
                    img.sprite = towerData.icon;
                    img.preserveAspect = true;
                    break;
                }
            }

            Button button = buttonObj.GetComponent<Button>();
            if (button != null)
            {
                button.onClick.AddListener(() => OnTowerSelected(towerData));

                bool canAfford = GameManager.Instance.HasEnoughGold(towerData.levels[0].cost);
                button.interactable = canAfford;
            }
        }

        public void OnTowerSelected(TowerData towerData)
        {
            Debug.Log($"📞 OnTowerSelected 被调用！塔: {towerData?.towerName}, _currentSlot: {_currentSlot != null}");

            if (_currentSlot == null || towerData == null)
            {
                Debug.LogError("❌ _currentSlot 或 towerData 是 null！");
                return;
            }

            Debug.Log($"📦 准备放置塔: {towerData.towerName}, 消耗金币: {towerData.levels[0].cost}");

            bool success = _currentSlot.PlaceTower(towerData);
            Debug.Log($"📦 PlaceTower 返回: {success}");

            if (success)
            {
                Debug.Log("✅ 塔放置成功！");
                Hide();
            }
            else
            {
                Debug.LogWarning("⚠️ 塔放置失败！");
            }
        }

        public void UpdateButtonStates()
        {
            foreach (Transform child in _towerButtonContainer)
            {
                TowerButton button = child.GetComponent<TowerButton>();
                if (button != null)
                {
                    button.UpdateState();
                }
            }
        }

        private void OnEnable()
        {
            EventBus.Subscribe<GoldChangedEvent>(OnGoldChanged);
        }

        private void OnDisable()
        {
            EventBus.Unsubscribe<GoldChangedEvent>(OnGoldChanged);
        }

        private void OnGoldChanged(GoldChangedEvent e)
        {
            UpdateButtonStates();
        }
    }

    public class TowerButton : MonoBehaviour
    {
        [SerializeField] private Text _nameText;
        [SerializeField] private Text _costText;
        [SerializeField] private Text _damageText;
        [SerializeField] private Text _rangeText;
        [SerializeField] private Image _icon;

        private TowerData _towerData;
        private TowerSelectPanel _panel;

        public void Initialize(TowerData towerData, TowerSelectPanel panel)
        {
            _towerData = towerData;
            _panel = panel;

            if (_nameText != null)
            {
                _nameText.text = towerData.towerName;
            }

            TowerData.TowerStats stats = towerData.levels[0];
            if (_costText != null)
            {
                _costText.text = $"{stats.cost} G";
            }

            if (_damageText != null)
            {
                _damageText.text = $"伤害: {stats.damage}";
            }

            if (_rangeText != null)
            {
                _rangeText.text = $"范围: {stats.attackRange}";
            }

            if (towerData.icon != null)
            {
                if (_icon != null)
                {
                    _icon.sprite = towerData.icon;
                    _icon.gameObject.SetActive(true);
                }

                Image[] allImages = GetComponentsInChildren<Image>();
                foreach (var img in allImages)
                {
                    if (img.gameObject != gameObject && img.sprite == null)
                    {
                        img.sprite = towerData.icon;
                        img.preserveAspect = true;
                        break;
                    }
                }
            }
            else
            {
                if (_icon != null)
                {
                    _icon.gameObject.SetActive(false);
                }
            }

            UpdateState();

            Button button = GetComponent<Button>();
            if (button != null)
            {
                Debug.Log($"🔘 找到Button组件，准备添加点击监听器...");
                button.onClick.AddListener(OnClicked);
                Debug.Log($"🔘 点击监听器已添加！当前监听器数量: {button.onClick.GetPersistentEventCount()}");
            }
            else
            {
                Debug.LogError("❌ 找不到Button组件！");
            }
        }

        public void UpdateState()
        {
            Button button = GetComponent<Button>();
            if (button != null)
            {
                bool canAfford = GameManager.Instance.HasEnoughGold(_towerData.levels[0].cost);
                button.interactable = canAfford;

                Image image = GetComponent<Image>();
                if (image != null)
                {
                    image.color = canAfford ? Color.white : Color.grey;
                }
            }
        }

        private void OnClicked()
        {
            Debug.Log($"🖱️ TowerButton.OnClicked 被调用！塔: {_towerData?.towerName}, panel: {_panel != null}");

            if (_panel != null)
            {
                Debug.Log($"📞 调用 _panel.OnTowerSelected...");
                _panel.OnTowerSelected(_towerData);
            }
            else
            {
                Debug.LogError("❌ _panel 是 null！");
            }
        }
    }
}

using UnityEngine;

namespace TowerDefense.Core
{
    public abstract class Singleton<T> : MonoBehaviour where T : MonoBehaviour
    {
        private static T _instance;
        private static readonly object _lock = new object();
        private static bool _applicationIsQuitting = false;

        public static T Instance
        {
            get
            {
                if (_applicationIsQuitting)
                {
                    Debug.LogWarning($"[Singleton] Instance '{typeof(T)}' already destroyed. Returning null.");
                    return null;
                }

                lock (_lock)
                {
                    if (_instance == null)
                    {
                        _instance = FindObjectOfType<T>();

                        if (_instance == null)
                        {
                            GameObject singleton = new GameObject($"(Singleton) {typeof(T)}");
                            _instance = singleton.AddComponent<T>();
                            DontDestroyOnLoad(singleton);
                        }
                    }
                    return _instance;
                }
            }
        }

        protected virtual void Awake()
        {
            if (_instance == null)
            {
                _instance = this as T;
                transform.SetParent(null);
                DontDestroyOnLoad(gameObject);
            }
            else if (_instance != this)
            {
                Destroy(gameObject);
            }
        }

        protected virtual void OnDestroy()
        {
            if (_instance == this)
            {
                _applicationIsQuitting = true;
            }
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using System.Collections.Generic;
using TowerDefense.Data;

namespace TowerDefense.UI
{
    public class QuestPanel : MonoBehaviour
    {
        [Header("Panel")]
        [SerializeField] private GameObject _questPanel;
        [SerializeField] private Button _closeButton;

        [Header("Tabs")]
        [SerializeField] private Button _tabDaily;
        [SerializeField] private Button _tabMain;
        [SerializeField] private Button _tabAchievement;
        [SerializeField] private Button _tabEvent;
        [SerializeField] private Color _tabActiveColor = new Color(1f, 0.78f, 0.2f, 1f);
        [SerializeField] private Color _tabInactiveColor = new Color(0.3f, 0.6f, 0.3f, 1f);

        [Header("Content")]
        [SerializeField] private Transform _itemContainer;
        [SerializeField] private GameObject _questItemPrefab;

        [Header("Info Bar")]
        [SerializeField] private Text _resetTimerText;
        [SerializeField] private Text _activityText;

        [Header("Activity Bar")]
        [SerializeField] private Slider _activitySlider;
        [SerializeField] private Image[] _chestIcons;
        [SerializeField] private Sprite _chestLocked;
        [SerializeField] private Sprite _chestUnlocked;
        [SerializeField] private Sprite _chestClaimed;

        [Header("Data")]
        [SerializeField] private string _jsonPath = "Data/QuestItems";

        private QuestData _questData;
        private QuestCategory _currentCategory;
        private List<GameObject> _spawnedItems = new List<GameObject>();
        private Dictionary<QuestCategory, Button> _tabButtons = new Dictionary<QuestCategory, Button>();
        private GameObject _torchRoot;
        private MovingClouds _clouds;
        private ParticleSystem _snowParticles;
        private int _snowOriginalSortOrder;

        public void SetReferences(GameObject questPanel, Button closeButton, Button tabDaily, Button tabMain, Button tabAchievement, Button tabEvent, Transform itemContainer, GameObject questItemPrefab, Text resetTimerText, Text activityText, Slider activitySlider, Image[] chestIcons)
        {
            _questPanel = questPanel;
            _closeButton = closeButton;
            _tabDaily = tabDaily;
            _tabMain = tabMain;
            _tabAchievement = tabAchievement;
            _tabEvent = tabEvent;
            _itemContainer = itemContainer;
            _questItemPrefab = questItemPrefab;
            _resetTimerText = resetTimerText;
            _activityText = activityText;
            _activitySlider = activitySlider;
            _chestIcons = chestIcons;
        }

        private void Awake()
        {
            _tabButtons[QuestCategory.Daily] = _tabDaily;
            _tabButtons[QuestCategory.Main] = _tabMain;
            _tabButtons[QuestCategory.Achievement] = _tabAchievement;
            _tabButtons[QuestCategory.Event] = _tabEvent;

            if (_closeButton != null)
                _closeButton.onClick.AddListener(CloseQuest);

            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value != null)
                {
                    var cat = kvp.Key;
                    kvp.Value.onClick.AddListener(() => SwitchTab(cat));
                }
            }

            _torchRoot = GameObject.Find("火把");

            GameObject bgObj = GameObject.Find("背景");
            if (bgObj != null)
            {
                _clouds = bgObj.GetComponent<MovingClouds>();
                _snowParticles = bgObj.GetComponentInChildren<ParticleSystem>();
                if (_snowParticles != null)
                {
                    var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                    if (renderer != null)
                        _snowOriginalSortOrder = renderer.sortingOrder;
                }
            }

            LoadQuestData();
        }

        private void Start()
        {
            if (_questPanel != null)
                _questPanel.SetActive(false);
        }

        private void LoadQuestData()
        {
            var jsonFile = Resources.Load<TextAsset>(_jsonPath);
            if (jsonFile != null)
            {
                _questData = JsonUtility.FromJson<QuestData>(jsonFile.text);
                Debug.Log($"[QuestPanel] Loaded {_questData.items.Length} quests from JSON");
            }
            else
            {
                Debug.LogError($"[QuestPanel] Failed to load JSON: Resources/{_jsonPath}");
                _questData = new QuestData { items = new QuestItemData[0], dailyActivity = 0, dailyActivityMax = 120 };
            }
        }

        public void OpenQuest()
        {
            if (_questPanel != null)
                _questPanel.SetActive(true);

            if (_torchRoot != null)
                _torchRoot.SetActive(false);

            if (_clouds != null)
                _clouds.IsPaused = true;

            if (_snowParticles != null)
            {
                var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                if (renderer != null)
                    renderer.sortingOrder = -10;
                _snowParticles.Pause(true);
            }

            LoadQuestData();
            SwitchTab(QuestCategory.Daily);
        }

        public void CloseQuest()
        {
            if (_questPanel != null)
                _questPanel.SetActive(false);

            if (_torchRoot != null)
                _torchRoot.SetActive(true);

            if (_clouds != null)
                _clouds.IsPaused = false;

            if (_snowParticles != null)
            {
                var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                if (renderer != null)
                    renderer.sortingOrder = _snowOriginalSortOrder;
                _snowParticles.Play(true);
            }
        }

        private void SwitchTab(QuestCategory category)
        {
            _currentCategory = category;
            UpdateTabVisuals();
            RefreshItemList();
            UpdateInfoBar();
        }

        private void UpdateTabVisuals()
        {
            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value == null) continue;
                var colors = kvp.Value.colors;
                colors.normalColor = kvp.Key == _currentCategory ? _tabActiveColor : _tabInactiveColor;
                colors.selectedColor = colors.normalColor;
                colors.highlightedColor = kvp.Key == _currentCategory ? _tabActiveColor : new Color(0.8f, 0.8f, 0.8f, 1f);
                kvp.Value.colors = colors;
            }
        }

        private void UpdateInfoBar()
        {
            if (_activityText != null && _questData != null)
                _activityText.text = $"⭐ {_questData.dailyActivity}";

            if (_activitySlider != null && _questData != null)
            {
                _activitySlider.maxValue = _questData.dailyActivityMax;
                _activitySlider.value = _questData.dailyActivity;
            }

            UpdateChestIcons();
        }

        private void UpdateChestIcons()
        {
            if (_questData == null || _chestIcons == null) return;
            int[] thresholds = { 30, 60, 90, 120 };
            for (int i = 0; i < _chestIcons.Length && i < thresholds.Length; i++)
            {
                if (_chestIcons[i] == null) continue;
                _chestIcons[i].sprite = _questData.dailyActivity >= thresholds[i] ? _chestUnlocked : _chestLocked;
            }
        }

        private void RefreshItemList()
        {
            foreach (var item in _spawnedItems)
            {
                if (item != null) DestroyImmediate(item);
            }
            _spawnedItems.Clear();

            if (_itemContainer == null || _questItemPrefab == null)
            {
                Debug.LogWarning("[QuestPanel] Item container or prefab is null");
                return;
            }

            foreach (var questData in _questData.items)
            {
                if (questData.category != _currentCategory) continue;

                GameObject itemObj = Instantiate(_questItemPrefab, _itemContainer);
                itemObj.SetActive(true);
                _spawnedItems.Add(itemObj);

                var questItemUI = itemObj.GetComponent<QuestItemUI>();
                if (questItemUI != null)
                    questItemUI.Setup(questData, this);
            }
        }

        public void OnClaimClicked(QuestItemData questData)
        {
            if (questData.status != QuestStatus.Claimable)
            {
                Debug.Log($"[QuestPanel] {questData.name} 不可领取");
                return;
            }

            var wallet = PlayerWallet.Instance;
            if (wallet == null)
            {
                Debug.LogWarning("[QuestPanel] PlayerWallet not found");
                return;
            }

            if (questData.rewards != null)
            {
                foreach (var reward in questData.rewards)
                {
                    switch (reward.rewardType)
                    {
                        case RewardType.Gold: wallet.AddGold(reward.amount); break;
                        case RewardType.Diamond: wallet.AddDiamond(reward.amount); break;
                        case RewardType.Stamina: wallet.AddStamina(reward.amount); break;
                    }
                }
            }

            questData.status = QuestStatus.Claimed;
            _questData.dailyActivity += 10;
            Debug.Log($"[QuestPanel] 领取成功: {questData.name}");

            RefreshItemList();
            UpdateInfoBar();
        }

        public void OnGoToClicked(QuestItemData questData)
        {
            Debug.Log($"[QuestPanel] 前往: {questData.name}");
            CloseQuest();
        }

        public static string GetCategoryName(QuestCategory category)
        {
            return category switch
            {
                QuestCategory.Daily => "每日任务",
                QuestCategory.Main => "主线任务",
                QuestCategory.Achievement => "成就任务",
                QuestCategory.Event => "活动任务",
                _ => "未知"
            };
        }

        public static string GetRewardSymbol(RewardType type)
        {
            return type switch
            {
                RewardType.Gold => "🪙",
                RewardType.Diamond => "💎",
                RewardType.Stamina => "⚡",
                RewardType.Item => "📦",
                _ => ""
            };
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using TowerDefense.Data;

namespace TowerDefense.UI
{
    public class QuestItemUI : MonoBehaviour
    {
        [Header("UI References")]
        [SerializeField] private Image _iconImage;
        [SerializeField] private Text _nameText;
        [SerializeField] private Text _descText;
        [SerializeField] private Slider _progressSlider;
        [SerializeField] private Text _progressText;
        [SerializeField] private Image _rewardIcon;
        [SerializeField] private Text _rewardText;
        [SerializeField] private Button _actionButton;
        [SerializeField] private Text _actionText;
        [SerializeField] private GameObject _tagObject;
        [SerializeField] private Text _tagText;

        private QuestItemData _itemData;
        private QuestPanel _questPanel;

        public void SetReferences(Image iconImage, Text nameText, Text descText, Slider progressSlider, Text progressText, Image rewardIcon, Text rewardText, Button actionButton, Text actionText, GameObject tagObject, Text tagText)
        {
            _iconImage = iconImage;
            _nameText = nameText;
            _descText = descText;
            _progressSlider = progressSlider;
            _progressText = progressText;
            _rewardIcon = rewardIcon;
            _rewardText = rewardText;
            _actionButton = actionButton;
            _actionText = actionText;
            _tagObject = tagObject;
            _tagText = tagText;
        }

        public void Setup(QuestItemData itemData, QuestPanel questPanel)
        {
            _itemData = itemData;
            _questPanel = questPanel;

            // Name & Description
            if (_nameText != null)
                _nameText.text = itemData.name;

            if (_descText != null)
                _descText.text = itemData.description;

            // Progress
            if (_progressSlider != null)
            {
                _progressSlider.maxValue = itemData.targetCount;
                _progressSlider.value = itemData.currentCount;
            }

            if (_progressText != null)
                _progressText.text = $"{itemData.currentCount}/{itemData.targetCount}";

            // Icon
            if (_iconImage != null)
            {
                if (!string.IsNullOrEmpty(itemData.iconPath))
                {
                    var sprite = Resources.Load<Sprite>(itemData.iconPath);
                    if (sprite != null)
                    {
                        _iconImage.sprite = sprite;
                        _iconImage.color = Color.white;
                    }
                    else
                    {
                        SetCategoryFallbackColor(itemData.category);
                    }
                }
                else
                {
                    SetCategoryFallbackColor(itemData.category);
                }
            }

            // Reward
            if (itemData.rewards != null && itemData.rewards.Length > 0)
            {
                var reward = itemData.rewards[0];
                if (_rewardText != null)
                    _rewardText.text = $"x{reward.amount}";
            }

            // Tag
            if (_tagObject != null)
            {
                bool hasTag = !string.IsNullOrEmpty(itemData.tag);
                _tagObject.SetActive(hasTag);
                if (hasTag && _tagText != null)
                    _tagText.text = itemData.tag;
            }

            // Action Button
            if (_actionButton != null)
            {
                _actionButton.onClick.RemoveAllListeners();

                if (itemData.status == QuestStatus.Claimed)
                {
                    _actionButton.interactable = false;
                    if (_actionText != null)
                        _actionText.text = "已完成";
                }
                else if (itemData.status == QuestStatus.Claimable)
                {
                    _actionButton.interactable = true;
                    if (_actionText != null)
                        _actionText.text = "领取";

                    var colors = _actionButton.colors;
                    colors.normalColor = new Color(1f, 0.65f, 0.15f, 1f);
                    colors.highlightedColor = new Color(1f, 0.75f, 0.3f, 1f);
                    _actionButton.colors = colors;

                    _actionButton.onClick.AddListener(OnClaimClicked);
                }
                else
                {
                    _actionButton.interactable = true;
                    if (_actionText != null)
                        _actionText.text = "前往";

                    var colors = _actionButton.colors;
                    colors.normalColor = new Color(0.3f, 0.75f, 0.3f, 1f);
                    colors.highlightedColor = new Color(0.4f, 0.85f, 0.4f, 1f);
                    _actionButton.colors = colors;

                    _actionButton.onClick.AddListener(OnGoToClicked);
                }
            }
        }

        private void SetCategoryFallbackColor(QuestCategory category)
        {
            _iconImage.sprite = null;
            _iconImage.color = category switch
            {
                QuestCategory.Daily => new Color(1f, 0.85f, 0.2f, 1f),
                QuestCategory.Main => new Color(0.3f, 0.7f, 1f, 1f),
                QuestCategory.Achievement => new Color(0.8f, 0.5f, 1f, 1f),
                QuestCategory.Event => new Color(1f, 0.4f, 0.4f, 1f),
                _ => Color.white
            };
        }

        private void OnClaimClicked()
        {
            if (_questPanel != null && _itemData != null)
                _questPanel.OnClaimClicked(_itemData);
        }

        private void OnGoToClicked()
        {
            if (_questPanel != null && _itemData != null)
                _questPanel.OnGoToClicked(_itemData);
        }
    }
}

using UnityEngine;

namespace TowerDefense.Data
{
